import React, { useEffect, useState, useCallback, useRef } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import {
  Dialog,
  DialogContent,
  DialogTitle,
} from '@/components/ui/dialog';
import { Megaphone, Bell, ChevronLeft, ChevronRight } from 'lucide-react';
import { realtimeEngine } from '@/lib/RealtimeEngine';

interface AnnouncementMessage {
  id: string;
  content: string;
  sender_name: string;
}

export function GlobalAnnouncement() {
  const { user } = useAuth();
  // Message queue: all pending unread messages
  const [queue, setQueue] = useState<AnnouncementMessage[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isOpen, setIsOpen] = useState(false);
  const markedAsReadRef = useRef<Set<string>>(new Set());

  const addToQueue = useCallback((msg: AnnouncementMessage) => {
    setQueue(prev => {
      // Avoid duplicates
      if (prev.some(m => m.id === msg.id)) return prev;
      return [...prev, msg];
    });
    setIsOpen(true);
  }, []);

  useEffect(() => {
    if (!user) return;

    // 1. Fetch ALL unread broadcast messages on mount
    const fetchUnread = async () => {
      const { data: messages } = await supabase
        .from('messages')
        .select(`id, content, sender_id, profiles!messages_sender_id_fkey (full_name)`)
        .eq('receiver_id', user.id)
        .eq('is_read', false)
        .order('created_at', { ascending: true }) // oldest first
        .limit(20);

      if (messages && messages.length > 0) {
        const items: AnnouncementMessage[] = messages.map((msg: any) => ({
          id: msg.id,
          content: msg.content,
          sender_name: (msg.profiles as any)?.full_name || 'الإدارة',
        }));
        setQueue(items);
        setCurrentIndex(0);
        setIsOpen(true);
      }
    };

    fetchUnread();

    // 2. Real-time for NEW messages while user is online
    // Create inline handler to avoid recreating on every render
    const handleRealtimeMessage = async (payload: any) => {
      const newMsg = payload.new as any;
      if (markedAsReadRef.current.has(newMsg.id)) return;

      // Fetch sender name
      const { data: profile } = await supabase
        .from('profiles')
        .select('full_name')
        .eq('id', newMsg.sender_id)
        .single();

      addToQueue({
        id: newMsg.id,
        content: newMsg.content,
        sender_name: profile?.full_name || 'الإدارة',
      });
    };

    // Check if already subscribed to avoid duplicate subscriptions
    const channelName = `global-announcements-${user.id}`;
    const unsubscribe = realtimeEngine.subscribe(
      channelName,
      'messages',
      handleRealtimeMessage,
      { event: 'INSERT', filter: `receiver_id=eq.${user.id}` }
    );

    return () => {
      console.log('[GlobalAnnouncement] Cleaning up realtime subscription');
      unsubscribe();
    };
  }, [user?.id]); // Only depend on user.id, not the whole user object

  const markCurrentAsRead = async (id: string) => {
    if (markedAsReadRef.current.has(id)) return;
    markedAsReadRef.current.add(id);
    await supabase.from('messages').update({ is_read: true }).eq('id', id);
  };

  const handleNext = async () => {
    const current = queue[currentIndex];
    if (current) await markCurrentAsRead(current.id);

    if (currentIndex < queue.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      // All messages read
      setIsOpen(false);
      setQueue([]);
      setCurrentIndex(0);
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) setCurrentIndex(prev => prev - 1);
  };

  const currentMsg = queue[currentIndex];
  if (!currentMsg) return null;

  return (
    <Dialog open={isOpen} onOpenChange={(open) => {
      if (!open) {
        // Mark current as read when closing
        if (currentMsg) markCurrentAsRead(currentMsg.id);
        setIsOpen(false);
      }
    }}>
      <DialogContent
        className="sm:max-w-[550px] border-none shadow-[0_32px_120px_rgba(15,23,42,0.3)] p-0 overflow-hidden rounded-[40px] bg-white"
        dir="rtl"
      >
        {/* Header */}
        <div className="bg-slate-900 p-10 text-white relative overflow-hidden">
          <div className="absolute top-[-40px] right-[-40px] w-64 h-64 bg-indigo-500/10 rounded-full blur-3xl pointer-events-none" />
          <div className="absolute bottom-[-20px] left-[-20px] w-48 h-48 bg-indigo-500/5 rounded-full blur-2xl pointer-events-none" />

          <div className="relative z-10 flex flex-col items-center text-center gap-4">
            <div className="w-20 h-20 rounded-[32px] bg-indigo-600 text-white flex items-center justify-center shadow-2xl shadow-indigo-600/40 animate-bounce">
              <Megaphone className="w-10 h-10" />
            </div>
            <DialogTitle className="text-2xl font-black tracking-tight leading-none">
              تنبيه إداري رسمي
            </DialogTitle>
            <p className="text-white/40 text-[10px] font-black uppercase tracking-[0.25em]">
              صادر عن: {currentMsg.sender_name}
            </p>

            {/* Queue indicator if multiple messages */}
            {queue.length > 1 && (
              <div className="flex items-center gap-2 mt-1">
                {queue.map((_, i) => (
                  <div
                    key={i}
                    className={`h-1.5 rounded-full transition-all duration-300 ${
                      i === currentIndex ? 'w-6 bg-indigo-400' : 'w-1.5 bg-white/20'
                    }`}
                  />
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Content */}
        <div className="p-10 space-y-8">
          <div className="bg-slate-50 p-8 rounded-[32px] border-2 border-slate-100 relative">
            <div className="absolute -top-4 -right-4 w-10 h-10 bg-white border-2 border-slate-100 rounded-full flex items-center justify-center text-slate-300">
              <Bell className="w-5 h-5" />
            </div>
            <p className="text-slate-900 text-lg leading-relaxed font-bold tracking-tight">
              "{currentMsg.content}"
            </p>
          </div>

          {/* Navigation buttons */}
          <div className="flex gap-3">
            {queue.length > 1 && currentIndex > 0 && (
              <button
                onClick={handlePrev}
                className="flex-1 h-14 rounded-[22px] bg-slate-100 text-slate-600 font-black text-xs gap-2 flex items-center justify-center hover:bg-slate-200 transition-all active:scale-95"
              >
                <ChevronRight className="w-4 h-4" />
                السابقة
              </button>
            )}

            <button
              onClick={handleNext}
              className="flex-1 h-14 rounded-[22px] bg-slate-900 text-white font-black text-xs flex items-center justify-center gap-2 hover:scale-[1.02] active:scale-95 transition-all shadow-xl shadow-slate-900/20"
            >
              {currentIndex < queue.length - 1 ? (
                <>
                  التالية
                  <ChevronLeft className="w-4 h-4" />
                  <span className="px-2 py-0.5 rounded-lg bg-white/10 text-white text-[9px] font-black">
                    {queue.length - currentIndex - 1} متبقية
                  </span>
                </>
              ) : (
                'تأكيد الاستلام والإغلاق'
              )}
            </button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useEffect, useState, useCallback, useRef } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { ShieldAlert, WifiOff, RefreshCw } from 'lucide-react';
import { queryClient } from '@/lib/queryClient';
import { realtimeEngine } from '@/lib/RealtimeEngine';

type ConnectionStatus = 'online' | 'offline' | 'error';

export function HealthMonitor() {
  const [status, setStatus] = useState<ConnectionStatus>('online');
  const [isRetrying, setIsRetrying] = useState(false);
  const [wasOffline, setWasOffline] = useState(false);
  const retryCountRef = useRef(0);
  const retryTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const refetchAll = useCallback(() => {
    // Invalidate ALL queries (not just active) to ensure fresh data on tab return
    // This forces React Query to refetch everything from the server
    queryClient.invalidateQueries();
  }, []);

  const validateSession = useCallback(async () => {
    try {
      const { data: { session }, error } = await supabase.auth.getSession();
      if (error || !session) {
        console.warn('⚠️ Session invalid on focus, AuthProvider will handle redirect.');
      }
    } catch (e) {
      console.error('❌ Error validating session on focus:', e);
    }
  }, []);

  const checkConnection = useCallback(async (): Promise<ConnectionStatus> => {
    if (!window.navigator.onLine) {
      return 'offline';
    }
    try {
      const { error } = await supabase.from('schools').select('id').limit(1).maybeSingle();
      if (error && error.code !== 'PGRST116') throw error;
      return 'online';
    } catch (err) {
      console.error('⚠️ DB health check failed:', err);
      return 'error';
    }
  }, []);

  const handleRetry = async () => {
    setIsRetrying(true);
    const newStatus = await checkConnection();
    setStatus(newStatus);
    setIsRetrying(false);
    if (newStatus === 'online') {
      retryCountRef.current = 0;
      refetchAll();
    }
  };

  useEffect(() => {
    checkConnection().then(setStatus);

    // Define handlers outside to ensure proper cleanup
    const handleOnline = () => setStatus('online');
    const handleOffline = () => setStatus('offline');

    const handleFocusOrVisible = async () => {
      if (document.visibilityState === 'visible') {
        console.log('👁️ Tab visible/focused, validating health...');

        // Step 1: Check connection status
        const newStatus = await checkConnection();
        setStatus(newStatus);

        if (newStatus === 'online') {
          // Step 2: Validate session
          await validateSession();

          // Step 3: Resync realtime channels (RealtimeEngine handles this robustly now)
          console.log('🔄 Triggering RealtimeEngine resync...');
          await realtimeEngine.resyncAll();

          // Step 4: Small delay to ensure channels are ready before refetching
          await new Promise(resolve => setTimeout(resolve, 1000));

          // Step 5: Check if resync was successful
          const resyncStatus = realtimeEngine.getSubscriptionStatus();
          const healthyChannels = Object.values(resyncStatus).filter((s: any) => s.isHealthy).length;
          const totalChannels = Object.keys(resyncStatus).length;

          console.log(`📊 Resync status: ${healthyChannels}/${totalChannels} channels healthy`);

          // If less than 50% of channels are healthy, log warning but DON'T reload page
          // React Query's refetchOnWindowFocus will handle data refresh automatically
          if (totalChannels > 0 && healthyChannels < totalChannels * 0.5) {
            console.warn(`⚠️ Low healthy channels: ${healthyChannels}/${totalChannels}. RealtimeEngine will auto-recover.`);
            // Don't force reload - let RealtimeEngine handle reconnection
            // The user will see a warning banner but data will still load via React Query
          }

          // Step 6: Resume any paused mutations (writes that failed while offline)
          await queryClient.resumePausedMutations();

          // Step 7: Invalidate active queries to trigger refetch
          refetchAll();

          // Track that we recovered from offline
          if (status === 'offline' || status === 'error') {
            setWasOffline(true);
            setTimeout(() => setWasOffline(false), 3000);
          }

          console.log('✅ Health check and resync complete');
        }
      }
    };

    // Register listeners with proper references
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    window.addEventListener('visibilitychange', handleFocusOrVisible);
    window.addEventListener('focus', handleFocusOrVisible);

    // Periodic health check every 60s
    const interval = setInterval(async () => {
      if (window.navigator.onLine) {
        const newStatus = await checkConnection();
        if (newStatus !== status) {
          console.log(`🔄 Connection status changed: ${status} → ${newStatus}`);
          setStatus(newStatus);
        }

        // If we're online but status shows error, try to recover
        if (newStatus === 'online' && status === 'error') {
          console.log('🔧 Attempting automatic recovery...');
          await realtimeEngine.resyncAll();
          refetchAll();
        }
      }
    }, 60000);

    // Proper cleanup
    return () => {
      clearInterval(interval);
      const currentTimer = retryTimerRef.current;
      if (currentTimer) clearTimeout(currentTimer);

      // Remove listeners with correct references
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      window.removeEventListener('visibilitychange', handleFocusOrVisible);
      window.removeEventListener('focus', handleFocusOrVisible);

      // Note: We don't destroy RealtimeEngine here as it's a singleton
      // that should persist for the app lifecycle
    };
  }, [checkConnection, validateSession, status, refetchAll]);

  // Show "reconnected" green banner briefly
  if (wasOffline && status === 'online') {
    return (
      <div className="fixed top-4 left-1/2 -translate-x-1/2 z-[10000] animate-in slide-in-from-top-4 duration-500" dir="rtl">
        <div className="px-6 py-3 rounded-full shadow-2xl flex items-center gap-3 bg-emerald-500 border border-emerald-600 text-white">
          <div className="w-2 h-2 rounded-full bg-white animate-pulse" />
          <span className="text-sm font-black tracking-tight">تم استعادة الاتصال بنجاح</span>
        </div>
      </div>
    );
  }

  if (status === 'online') return null;

  return (
    <div className="fixed top-4 left-1/2 -translate-x-1/2 z-[10000] animate-in slide-in-from-top-4 duration-500" dir="rtl">
      <div className={`px-6 py-3 rounded-full shadow-2xl flex items-center gap-4 border ${
        status === 'offline' ? 'bg-amber-500 border-amber-600' : 'bg-rose-500 border-rose-600'
      } text-white`}>
        {status === 'offline' ? <WifiOff className="w-5 h-5" /> : <ShieldAlert className="w-5 h-5" />}

        <span className="text-sm font-black tracking-tight">
          {status === 'offline' ? 'لا يوجد اتصال بالإنترنت — جاري إعادة المحاولة...' : 'خطأ في الاتصال بقاعدة البيانات'}
        </span>

        <button 
          onClick={handleRetry} 
          disabled={isRetrying}
          className="p-2 rounded-lg bg-white/20 hover:bg-white/30 transition-colors disabled:opacity-50"
          title="إعادة المحاولة"
        >
          <RefreshCw className={`w-4 h-4 ${isRetrying ? 'animate-spin' : ''}`} />
        </button>

        <button 
          onClick={() => window.location.reload()} 
          className="p-2 rounded-lg bg-white/20 hover:bg-white/30 transition-colors"
          title="إعادة تحميل الصفحة"
        >
          <RefreshCw className="w-4 h-4" />
        </button>
      </div>
    </div>
  );
}

import { useEffect, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

export default function PwaManager() {
  const { user } = useAuth();

  const updateManifest = useCallback(async () => {
    let name = "المدرسة الذكية";
    let shortName = "المدرسة";
    const defaultIcon = "/icons/icon-192.png";
    let icon = defaultIcon;
    let slug = "";
    let themeColor = "#1e293b";

    // 1. Determine school context
    if (user?.schoolId) {
      try {
        const { data, error } = await supabase
          .from('schools')
          .select('name, slug, logo_url')
          .eq('id', user.schoolId)
          .maybeSingle();

        if (error) {
          console.error('Error fetching PWA school data:', error);
        } else if (data) {
          const school = data as any;
          name = school.name;
          shortName = school.name.split(' ')[0];
          icon = school.logo_url || "/icons/icon-192.png";
          slug = school.slug;
          themeColor = "#1e293b";
        }
      } catch (err) {
        console.error('Fatal error in PwaManager fetch:', err);
      }
    } else {
      // Check URL for registration slugs or query params
      const pathParts = window.location.pathname.split('/');
      const isReg = pathParts.includes('register');
      const urlSlug = pathParts[pathParts.length - 1];
      const params = new URLSearchParams(window.location.search);
      const querySlug = params.get('school');

      const finalSlug = querySlug || (isReg ? urlSlug : null);

      if (finalSlug) {
         try {
           const { data, error } = await supabase
            .from('schools')
            .select('name, slug, logo_url')
            .eq('slug', finalSlug)
            .maybeSingle();

          if (error) {
            console.error('Error fetching PWA school data by slug:', error);
          } else if (data) {
            const school = data as any;
            name = school.name;
            shortName = school.name.split(' ')[0];
            icon = school.logo_url || "/icons/icon-192.png";
            slug = school.slug;
            themeColor = "#1e293b";
          }
        } catch (err) {
          console.error('Fatal error in PwaManager fetch by slug:', err);
        }
      }
    }

    // Add cache busting to icon to force refresh when changed in dashboard
    const timestamp = Date.now();
    const cacheBustIcon = icon.includes('?') ? `${icon}&v=${timestamp}` : `${icon}?v=${timestamp}`;

    // @ts-ignore - Deep type instantiation
    const manifest = {
      name: name,
      short_name: shortName,
      description: `نظام إدارة ${name} الذكي`,
      start_url: window.location.origin + (slug ? `/?school=${slug}` : "/"),
      display: "standalone",
      background_color: "#0a0f1e",
      theme_color: themeColor,
      icons: [
        {
          src: cacheBustIcon.startsWith('http') ? cacheBustIcon : window.location.origin + (cacheBustIcon.startsWith('/') ? cacheBustIcon : '/' + cacheBustIcon),
          sizes: "192x192",
          type: "image/png",
          purpose: "any maskable"
        },
        {
          src: cacheBustIcon.startsWith('http') ? cacheBustIcon : window.location.origin + (cacheBustIcon.startsWith('/') ? cacheBustIcon : '/' + cacheBustIcon),
          sizes: "512x512",
          type: "image/png"
        }
      ]
    };

    const stringManifest = JSON.stringify(manifest);
    const blob = new Blob([stringManifest], { type: 'application/json' });
    const manifestURL = URL.createObjectURL(blob);

    // 3. Update DOM
    const link = document.querySelector('link[rel="manifest"]') as HTMLLinkElement;
    if (link) {
      link.href = manifestURL;
    }

    // 4. Update Title & Favicon & Theme Color
    document.title = name;

    const updateIcon = (rel: string, href: string) => {
      let link = document.querySelector(`link[rel="${rel}"]`) as HTMLLinkElement;
      if (!link) {
        link = document.createElement('link');
        link.rel = rel;
        document.head.appendChild(link);
      }
      link.href = href;
    };

    const finalIcon = cacheBustIcon.startsWith('http') 
      ? cacheBustIcon 
      : window.location.origin + (cacheBustIcon.startsWith('/') ? cacheBustIcon : '/' + cacheBustIcon);

    updateIcon('icon', finalIcon);
    updateIcon('apple-touch-icon', finalIcon);
    updateIcon('shortcut icon', finalIcon);

    let metaTheme = document.querySelector("meta[name='theme-color']") as HTMLMetaElement;
    if (!metaTheme) {
      metaTheme = document.createElement('meta');
      metaTheme.name = 'theme-color';
      document.head.appendChild(metaTheme);
    }
    metaTheme.content = themeColor;
  }, [user?.schoolId]);

  useEffect(() => {
    updateManifest();

    // No realtime subscription needed - manifest updates on auth change only
    // Realtime engine was causing "cannot add postgres_changes after subscribe()" error

    return () => {
      // Cleanup if needed
    };
  }, [user?.schoolId, updateManifest]);

  return null;
}

import { useState } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useClassStudents, useSendMessage } from '@/hooks/queries';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import { Search, User, Send, Users, ArrowLeft } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Badge } from '@/components/ui/badge';
import { QueryStateHandler } from '@/components/QueryStateHandler';

interface ClassMessagesViewProps {
  classId: string;
  className: string;
}

export default function ClassMessagesView({ classId, className }: ClassMessagesViewProps) {
  const { user } = useAuth();
  const { toast } = useToast();
  const [search, setSearch] = useState('');
  const [selectedStudent, setSelectedStudent] = useState<any>(null);
  const [messageContent, setMessageContent] = useState('');
  const [studentParents, setStudentParents] = useState<any[]>([]);
  const [loadingParents, setLoadingParents] = useState(false);

  // Fetch students for this class
  const { data: studentsData, isLoading, error, refetch } = useClassStudents(classId);
  const students = studentsData || [];

  const sendMessageMutation = useSendMessage();

  // Filter students by search
  const filteredStudents = students.filter((s: any) => 
    s.name?.toLowerCase().includes(search.toLowerCase())
  );

  // Fetch parents for selected student
  const fetchStudentParents = async (studentId: string) => {
    setLoadingParents(true);
    try {
      // Step 1: Get parent_ids from student_parents
      const { data: parentLinks, error: linksError } = await supabase
        .from('student_parents')
        .select('parent_id')
        .eq('student_id', studentId);

      if (linksError) {
        throw linksError;
      }
      
      // If we found links, get parent profiles
      if (parentLinks && parentLinks.length > 0) {
        const parentIds = parentLinks.map(link => link.parent_id);
        
        // Try fetching from profiles first
        let { data: parentProfiles, error: profilesError } = await supabase
          .from('profiles')
          .select('id, full_name')
          .in('id', parentIds);

        if (profilesError) {
          // Profiles query failed, will use fallback below
        }
        
        // If profiles query returned empty, fetch basic info directly
        if (!parentProfiles || parentProfiles.length === 0) {
          // Fallback: create minimal parent objects with IDs only
          parentProfiles = parentIds.map(id => ({
            id: id,
            full_name: 'ولي الأمر'
          }));
        }
        
        setStudentParents(parentProfiles || []);
      } else {
        // No links found - try to find parent by phone number
        const student = students.find((s: any) => s.id === studentId);
        const parentPhone = student?.parent_phone;
        
        if (parentPhone) {
          // Try to find a parent profile with this phone
          const { data: potentialParents, error: phoneError } = await supabase
            .from('profiles')
            .select('id, full_name, phone')
            .eq('phone', parentPhone)
            .limit(1);
          
          if (phoneError) throw phoneError;
          
          if (potentialParents && potentialParents.length > 0) {
            // Found a parent! Create the link
            const parent = potentialParents[0];
            const { error: insertError } = await supabase
              .from('student_parents')
              .insert({
                student_id: studentId,
                parent_id: parent.id,
                school_id: user?.schoolId
              });
            
            if (!insertError) {
              // Link created successfully
              setStudentParents([parent]);
              toast({
                title: 'تم ربط ولي الأمر',
                description: `تم ربط الطالب بولي الأمر: ${parent.full_name}`,
              });
            } else {
              setStudentParents([parent]);
            }
          } else {
            setStudentParents([]);
          }
        } else {
          setStudentParents([]);
        }
      }
    } catch (error: any) {
      toast({
        title: 'خطأ',
        description: 'فشل في جلب بيانات أولياء الأمور',
        variant: 'destructive',
      });
    } finally {
      setLoadingParents(false);
    }
  };

  const handleStudentClick = (student: any) => {
    setSelectedStudent(student);
    fetchStudentParents(student.id);
    setMessageContent('');
  };

  const handleSendMessage = async () => {
    if (!messageContent.trim()) {
      toast({ title: 'خطأ', description: 'يرجى كتابة الرسالة', variant: 'destructive' });
      return;
    }

    if (studentParents.length === 0) {
      toast({ title: 'خطأ', description: 'لا يوجد أولياء أمور مرتبطون بهذا الطالب', variant: 'destructive' });
      return;
    }

    try {
      const parentIds = studentParents.map((parent: any) => parent.id);
      
      await sendMessageMutation.mutateAsync({
        targets: parentIds,
        content: messageContent.trim(),
        senderName: user?.fullName || 'المعلم',
        studentId: selectedStudent.id,
      });

      toast({
        title: 'تم الإرسال',
        description: `تم إرسال الرسالة إلى ${parentIds.length} ولي أمر`,
      });

      setMessageContent('');
      setSelectedStudent(null);
      setStudentParents([]);
    } catch (error: any) {
      toast({
        title: 'خطأ في الإرسال',
        description: error.message,
        variant: 'destructive',
      });
    }
  };

  // If student is selected, show message composition
  if (selectedStudent) {
    return (
      <div className="space-y-8">
        {/* Back Button */}
        <button
          onClick={() => {
            setSelectedStudent(null);
            setStudentParents([]);
            setMessageContent('');
          }}
          className="flex items-center gap-3 text-slate-600 hover:text-indigo-600 font-bold transition-colors text-lg"
        >
          <ArrowLeft className="w-5 h-5" />
          <span>العودة لقائمة الطلاب</span>
        </button>

        {/* Student Info Card */}
        <div className="bg-gradient-to-r from-blue-500 to-blue-600 p-8 rounded-[32px] text-white">
          <div className="flex items-center gap-5">
            <div className="w-16 h-16 rounded-2xl bg-white/20 flex items-center justify-center text-2xl font-black">
              {selectedStudent.name?.charAt(0)}
            </div>
            <div>
              <h3 className="text-2xl font-black">{selectedStudent.name}</h3>
              <p className="text-blue-100 text-sm mt-1">{className}</p>
            </div>
          </div>
        </div>

        {/* Parents Info */}
        {loadingParents ? (
          <div className="flex items-center justify-center py-12">
            <div className="w-10 h-10 border-4 border-blue-200 border-t-blue-600 rounded-full animate-spin" />
          </div>
        ) : studentParents.length > 0 ? (
          <div className="bg-white p-6 rounded-[24px] border border-slate-100">
            <h4 className="text-sm font-black text-slate-700 mb-4">أولياء الأمور:</h4>
            <div className="flex flex-wrap gap-3">
              {studentParents.map((parent: any) => (
                <Badge key={parent.id} className="bg-emerald-100 text-emerald-700 px-4 py-2 text-sm">
                  <User className="w-3 h-3 ml-1" />
                  {parent.full_name || 'ولي الأمر'}
                </Badge>
              ))}
            </div>
          </div>
        ) : (
          <div className="bg-amber-50 border-2 border-amber-200 p-6 rounded-[24px]">
            <p className="text-sm font-bold text-amber-700 mb-2">لا يوجد أولياء أمور مرتبطون بهذا الطالب</p>
            {selectedStudent.parent_phone ? (
              <p className="text-xs text-amber-600">رقم ولي الأمر مسجل: {selectedStudent.parent_phone}</p>
            ) : (
              <p className="text-xs text-amber-600">يرجى إضافة رقم هاتف ولي الأمر من صفحة تفاصيل الطالب أولاً</p>
            )}
          </div>
        )}

        {/* Message Composition */}
        <div className="bg-white p-8 rounded-[32px] border border-slate-100 space-y-6">
          <div>
            <label className="text-sm font-black text-slate-700 mb-3 block">نص الرسالة</label>
            <Textarea
              placeholder="اكتب رسالتك لولي الأمر هنا..."
              value={messageContent}
              onChange={(e) => setMessageContent(e.target.value)}
              className="min-h-[200px] p-6 rounded-2xl bg-slate-50 border-none text-base font-medium resize-none"
            />
          </div>

          <Button
            onClick={handleSendMessage}
            disabled={sendMessageMutation.isPending || studentParents.length === 0}
            className="w-full h-14 rounded-2xl bg-blue-600 text-white font-black text-lg hover:bg-blue-700 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {sendMessageMutation.isPending ? (
              'جاري الإرسال...'
            ) : studentParents.length === 0 ? (
              'لا يوجد ولي أمر مرتبط'
            ) : (
              <>
                إرسال الرسالة
                <Send className="w-5 h-5 mr-2 rotate-180" />
              </>
            )}
          </Button>
        </div>
      </div>
    );
  }

  // Show students list
  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="bg-gradient-to-r from-blue-500 to-blue-600 p-8 rounded-[32px] text-white">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-5">
            <div className="w-14 h-14 rounded-2xl bg-white/20 flex items-center justify-center">
              <Users className="w-7 h-7" />
            </div>
            <div>
              <h2 className="text-2xl font-black">رسائل لأولياء الأمور</h2>
              <p className="text-blue-100 text-sm mt-1">{className} - اختر طالباً لإرسال رسالة</p>
            </div>
          </div>
        </div>
      </div>

      {/* Search */}
      <div className="relative">
        <Search className="absolute right-5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
        <Input
          placeholder="ابحث عن طالب..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="h-14 pr-14 pl-6 rounded-2xl bg-white border-slate-200 font-bold text-base"
        />
      </div>

      {/* Students Grid */}
      <QueryStateHandler
        loading={isLoading}
        error={error}
        data={students}
        onRetry={refetch}
        loadingMessage="جاري تحميل الطلاب..."
        emptyMessage="لا يوجد طلاب في هذا الفصل"
        isEmpty={filteredStudents.length === 0}
      >
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredStudents.map((student: any) => (
            <button
              key={student.id}
              onClick={() => handleStudentClick(student)}
              className="bg-white p-6 rounded-[24px] border-2 border-slate-100 hover:border-blue-200 hover:bg-blue-50/50 transition-all text-right group"
            >
              <div className="flex items-center gap-4">
                <div className="w-14 h-14 rounded-xl bg-blue-100 flex items-center justify-center text-blue-600 font-black text-xl group-hover:bg-blue-600 group-hover:text-white transition-all">
                  {student.name?.charAt(0)}
                </div>
                <div className="flex-1">
                  <h3 className="font-black text-slate-900 text-lg">{student.name}</h3>
                  <p className="text-xs text-slate-500 mt-1">انقر لإرسال رسالة لولي الأمر</p>
                </div>
              </div>
            </button>
          ))}
        </div>
      </QueryStateHandler>
    </div>
  );
}

